# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

import flask
import graphene
from flask_graphql import GraphQLView

# --- Mock Data ---
products_data = {
    "1": {"id": "1", "name": "Laptop Pro", "description": "Powerful laptop for professionals", "price": 1200.00, "category_id": "C1", "review_ids": ["R1", "R2"]},
    "2": {"id": "2", "name": "Wireless Mouse", "description": "Ergonomic wireless mouse", "price": 25.00, "category_id": "C2", "review_ids": ["R3"]},
    "3": {"id": "3", "name": "Mechanical Keyboard", "description": "Tactile mechanical keyboard", "price": 80.00, "category_id": "C2", "review_ids": []},
    "4": {"id": "4", "name": "USB-C Hub", "description": "Multi-port USB-C adapter", "price": 45.00, "category_id": "C2", "review_ids": []},
    "5": {"id": "5", "name": "Monitor Ultra HD", "description": "4K monitor with vibrant colors", "price": 350.00, "category_id": "C1", "review_ids": ["R4"]},
}

categories_data = {
    "C1": {"id": "C1", "name": "Electronics", "description": "Devices and Gadgets"},
    "C2": {"id": "C2", "name": "Computer Peripherals", "description": "Accessories for computers"},
}

reviews_data = {
    "R1": {"id": "R1", "product_id": "1", "user_id": "U1", "rating": 5, "comment": "Amazing performance!"},
    "R2": {"id": "R2", "product_id": "1", "user_id": "U2", "rating": 4, "comment": "Good value for money."},
    "R3": {"id": "R3", "product_id": "2", "user_id": "U1", "rating": 5, "comment": "Very comfortable and precise."},
    "R4": {"id": "R4", "product_id": "5", "user_id": "U3", "rating": 4, "comment": "Great picture quality."},
}

users_data = {
    "U1": {"id": "U1", "username": "alice"},
    "U2": {"id": "U2", "username": "bob"},
    "U3": {"id": "U3", "username": "charlie"},
}

# --- Graphene Schema ---

class User(graphene.ObjectType):
    id = graphene.ID()
    username = graphene.String()

class Review(graphene.ObjectType):
    id = graphene.ID()
    rating = graphene.Int()
    comment = graphene.String()
    product = graphene.Field(lambda: Product)
    user = graphene.Field(User)

    def resolve_product(root, info):
        return products_data.get(root.product_id)

    def resolve_user(root, info):
        return users_data.get(root.user_id)

class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    products = graphene.List(lambda: Product)

    def resolve_products(root, info):
        return [p for p in products_data.values() if p["category_id"] == root.id]

class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category = graphene.Field(Category)
    reviews = graphene.List(Review)

    def resolve_category(root, info):
        return categories_data.get(root.category_id)

    def resolve_reviews(root, info):
        return [reviews_data.get(review_id) for review_id in root.review_ids if review_id in reviews_data]

class Query(graphene.ObjectType):
    product = graphene.Field(Product, id=graphene.ID(required=True))
    products = graphene.List(Product)
    category = graphene.Field(Category, id=graphene.ID(required=True))
    categories = graphene.List(Category)
    review = graphene.Field(Review, id=graphene.ID(required=True))
    reviews = graphene.List(Review)

    def resolve_product(root, info, id):
        return products_data.get(id)

    def resolve_products(root, info):
        return list(products_data.values())

    def resolve_category(root, info, id):
        return categories_data.get(id)

    def resolve_categories(root, info):
        return list(categories_data.values())

    def resolve_review(root, info, id):
        return reviews_data.get(id)

    def resolve_reviews(root, info):
        return list(reviews_data.values())

schema = graphene.Schema(query=Query)

# --- Flask App ---
app = flask.Flask(__name__)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True # Enable GraphiQL for introspection and testing
    )
)

if __name__ == '__main__':
    app.run(debug=True)